// 获取 "key" 的值
var key = java.get('key');  // 这里假设 java.get() 是从某处获取参数
var url = "https://69shu.biz/all.html";

// 使用 java.ajax 获取网页内容
var html = java.ajax(url);
html = org.jsoup.Jsoup.parse(html);  // 使用 Jsoup 解析 HTML 内容

// 定义一个空数组，用于存储符合条件的 <a> 标签的 href 和 text
var resultList = [];

// 查找 class="home-all" 内的所有 <a> 标签
var links = html.select('.home-all a');

// 遍历所有 <a> 标签
links.forEach(function(link) {
    var linkText = link.text();  // 获取 <a> 标签的文本内容
    var linkHref = link.attr("href");  // 获取 <a> 标签的 href 属性

    // 如果文本中包含特定的 'key'，则将该链接存入 resultList 数组
    if (linkText.contains(key)) {
        resultList.push({
            href: linkHref,
            text: linkText
        });
    }
});

// 输出符合条件的链接列表
resultList

